WITH race AS (
    SELECT raceId FROM races WHERE year = 2008 AND name = 'Australian Grand Prix'
),
champ AS (
    SELECT milliseconds FROM results WHERE raceId = (SELECT raceId FROM race) AND positionOrder = 1
),
last AS (
    SELECT milliseconds FROM results WHERE raceId = (SELECT raceId FROM race) AND positionOrder = (
        SELECT MAX(positionOrder) FROM results WHERE raceId = (SELECT raceId FROM race) AND positionOrder > 0
    )
)
SELECT ((last.milliseconds - champ.milliseconds) * 100.0) / last.milliseconds AS percent_faster
FROM champ, last;	----- bird -----	formula_1
